```C [sol1-C]
int cmp(const void* a, const void* b) {
    return *(int*)a - *(int*)b; 
}

int partitionArray(int* nums, int numsSize, int k) {
    qsort(nums, numsSize, sizeof(int), cmp);
    int ans = 1;
    int rec = nums[0];
    for (int i = 0; i < numsSize; i++) {
        if (nums[i] - rec > k) {
            ans++;
            rec = nums[i];
        }
    }
    return ans;
}
```

